const ForestThreshold = float32(0.489717752)
const forestFeatureCount = 24

type forestNode struct {
	Feature   uint8
	Threshold float32
	Left      int32
	Right     int32
	Value     float32
}

func ForestApproved(v [Dims]float32) bool {
	return ForestScore(v) < ForestThreshold
}

func ForestScore(v [Dims]float32) float32 {
	x := forestFeatures(v)
	sum := float32(0)
	for _, tree := range forestTrees {
		idx := int32(0)
		for {
			n := tree[idx]
			if n.Left < 0 {
				sum += n.Value
				break
			}
			if x[n.Feature] <= n.Threshold {
				idx = n.Left
			} else {
				idx = n.Right
			}
		}
	}
	return sum / float32(len(forestTrees))
}

func forestFeatures(v [Dims]float32) [forestFeatureCount]float32 {
	lastNull := float32(0)
	if v[5] < 0 {
		lastNull = 1
	}
	return [forestFeatureCount]float32{
		v[0], v[1], v[2], v[3], v[4], v[5], v[6], v[7],
		v[8], v[9], v[10], v[11], v[12], v[13], lastNull,
		v[0] * v[7], v[0] * v[11], v[7] * v[11],
		v[2] * v[8], v[9] * (1 - v[10]), v[12] * v[11],
		v[0] * v[12], v[7] * v[12], v[8] * v[11],
	}
}

